#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=3e5,M=8e5+10,NN=110,Mod=20071027;
int ch[M][26],cnt;bool vis[M];
inline void ins(char *s)
{
	int len=strlen(s),p=0;
	rep(0,len-1,i){int &x=ch[p][s[i]-'a'];p=(x?x:(x=++cnt));}
	vis[p]=1;return;
}
char s[N],t[NN];int dp[N],T;
inline void Solve()
{
	cnt=0;memset(ch,0,sizeof(ch));int len=strlen(s);
	memset(vis,0,sizeof(vis));memset(dp,0,sizeof(dp));
	int n=read();rep(1,n,i)scanf("%s",t),ins(t);
	dp[len]=1;drep(len-1,0,i)
	{
		int p=0;rep(i,len-1,j)
		{
			int c=s[j]-'a';if(!ch[p][c])break;
			p=ch[p][c];if(vis[p])dp[i]=(dp[i]+dp[j+1])%Mod;
		}
	}
	printf("Case %d: %d\n",++T,dp[0]);
}
int main(){while(~scanf("%s",s))Solve();return 0;}
